EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")

USERS = {
    1: {
        "id": 1,
        "email": "user@example.com",
        "password_hash": generate_password_hash("password"),
        "twofa": {"enabled": False, "method": None},
    }
}


def get_current_user():
    user_id = session.get("user_id")
    if not user_id:
        return None
    return USERS.get(user_id)


def require_auth():
    user = get_current_user()
    if not user:
        abort(401)
    return user


def validate_email(email: str) -> bool:
    if not isinstance(email, str):
        return False
    email = email.strip()
    return bool(email) and len(email) <= 254 and EMAIL_RE.match(email) is not None


def validate_password(password: str) -> bool:
    if not isinstance(password, str):
        return False
    if len(password) < 8 or len(password) > 256:
        return False
    return True


def validate_twofa(twofa) -> tuple[bool, str | None]:
    if not isinstance(twofa, dict):
        return False, "twofa must be an object"
    enabled = twofa.get("enabled", None)
    method = twofa.get("method", None)
    if not isinstance(enabled, bool):
        return False, "twofa.enabled must be boolean"
    if not enabled:
        if method not in (None, "", "none"):
            return False, "twofa.method must be null/none when disabled"
        return True, None
    if method not in ("totp", "sms", "webauthn"):
        return False, "twofa.method must be one of: totp, sms, webauthn"
    return True, None


@app.post("/api/profile")
def update_profile():
    user = require_auth()
    payload = request.get_json(silent=True)
    if payload is None or not isinstance(payload, dict):
        return jsonify({"error": "invalid_json"}), 400

    allowed_keys = {"email", "password", "twofa"}
    unknown = set(payload.keys()) - allowed_keys
    if unknown:
        return jsonify({"error": "unknown_fields", "fields": sorted(unknown)}), 400

    updated = False

    if "email" in payload:
        email = payload.get("email")
        if email is None:
            return jsonify({"error": "email_required"}), 400
        if not validate_email(email):
            return jsonify({"error": "invalid_email"}), 400
        email = email.strip().lower()
        if email != user["email"]:
            for uid, u in USERS.items():
                if uid != user["id"] and u["email"].lower() == email:
                    return jsonify({"error": "email_in_use"}), 409
            user["email"] = email
            updated = True

    if "password" in payload:
        password = payload.get("password")
        if password is None:
            return jsonify({"error": "password_required"}), 400
        if not validate_password(password):
            return jsonify({"error": "invalid_password"}), 400
        user["password_hash"] = generate_password_hash(password)
        updated = True

    if "twofa" in payload:
        ok, err = validate_twofa(payload.get("twofa"))
        if not ok:
            return jsonify({"error": "invalid_twofa", "detail": err}), 400
        twofa = payload["twofa"]
        enabled = bool(twofa["enabled"])
        method = twofa.get("method", None)
        if not enabled:
            method = None
        if user["twofa"].get("enabled") != enabled or user["twofa"].get("method") != method:
            user["twofa"] = {"enabled": enabled, "method": method}
            updated = True

    if not updated:
        return "", 204

    return jsonify(
        {
            "id": user["id"],
            "email": user["email"],
            "twofa": user["twofa"],
        }
    ), 200


